mod sock5_proxy;

use sock5_proxy::Sock5Proxy;
use base64::{self, read};
use hyper::{Client, Request};
use std::fs::File;
use std::io::{self, BufRead, BufReader, Read};
use std::path::PathBuf;
use std::process;
use std::str::FromStr;
use std::vec;

#[tokio::main]
async fn main() {
    let proxy = Sock5Proxy::new();

    proxy.start().await;
}

type Result<T> = std::result::Result<T, Box<dyn std::error::Error + Send + Sync>>;

struct SsrNode {}

fn get() -> Result<()> {
    let raw_data = "".as_bytes();
    let mut buf = BufReader::new(raw_data);

    let config = base64::Config::new(base64::CharacterSet::Standard, false);

    let mut buf_reader = BufReader::new(read::DecoderReader::new(&mut buf, config));

    let mut ssr_nodes: Vec<String> = Vec::new();
    loop {
        let mut raw_node_data = String::new();
        let result = buf_reader.read_line(&mut raw_node_data).unwrap();
        if result == 0 {
            // EOF
            break;
        }


        let read_node_data = match raw_node_data.strip_prefix("ssr://") {
            None => continue,
            Some(s) => s,
        };

        let bytes = match base64::decode_config(read_node_data, base64::Config::new(base64::CharacterSet::Standard, false)) {
            Ok(bytes) => match String::from_utf8(bytes) {
                Err(_) => continue,
                Ok(s) => s,
            },
            Err(_) => continue,
        };

        ssr_nodes.push(bytes);
    }
    return Result::Ok(());
}
